# HARNESS — not normative semantics. Delegates all execution to build/extracted_vm_runner (OCaml).
# DO NOT EDIT. Generated shim — all logic lives in thielecpu/vm.py (Coq extraction).
"""Thin re-export shim. All VM semantics live in thielecpu/vm.py generated by scripts/forge_vm.py."""
from __future__ import annotations

import os
import sys
from pathlib import Path
from typing import Any, Dict, List, Optional

sys.path.insert(0, str(Path(__file__).parent.parent))

from thielecpu import vm as _extracted_vm
from thielecpu.vm import (
    REG_COUNT,
    MEM_SIZE,
    TENSOR_SIZE,
    CSRState,
    partitionGraph,
    run_text_program,
    vm_run,
    vm_apply,
    _parse_instruction_dict,
    _parse_int,
    _parse_region,
)

_RUNNER_PATH = Path(__file__).parent / "extracted_vm_runner"


def VMState(
    pc: int = 0,
    mu: int = 0,
    err: bool = False,
    regs: Optional[List[int]] = None,
    mem: Optional[List[int]] = None,
    csrs: Optional[Dict[str, int]] = None,
    graph=None,
    modules=None,
    mu_tensor: Optional[List[int]] = None,
    logic_acc: int = 0,
    mstatus: int = 0,
    certified: bool = False,
    witness: Optional[List[int]] = None,
) -> _extracted_vm.VMState:
    """Factory: create a thielecpu.vm.VMState from flat keyword args."""
    if csrs is None or isinstance(csrs, dict):
        d = csrs or {}
        csr_obj = CSRState(
            csr_cert_addr=int(d.get("cert_addr", 0)),
            csr_status=int(d.get("status", 0)),
            csr_err=int(d.get("err", 0)),
            csr_heap_base=int(d.get("heap_base", 0)),
        )
    else:
        csr_obj = csrs
    graph_obj = graph if isinstance(graph, partitionGraph) else partitionGraph()
    return _extracted_vm.VMState(
        vm_pc=pc,
        vm_mu=mu,
        vm_err=err,
        vm_regs=list(regs) if regs is not None else [0] * REG_COUNT,
        vm_mem=list(mem) if mem is not None else [0] * MEM_SIZE,
        vm_csrs=csr_obj,
        vm_graph=graph_obj,
        vm_mu_tensor=list(mu_tensor) if mu_tensor is not None else [0] * TENSOR_SIZE,
        vm_logic_acc=logic_acc,
        vm_mstatus=mstatus,
        vm_witness=list(witness) if witness is not None else [0] * 8,
        vm_certified=certified,
    )


def _runner_available() -> bool:
    return _extracted_vm._runner_available()


def _strict_backend_required() -> bool:
    raw = os.getenv("THIELE_STRICT_VM_BACKEND", "0").strip().lower()
    return raw in {"1", "true", "yes", "on"}


# These are module-level so tests can monkeypatch them.
_run_extracted = run_text_program
_run_python = run_text_program
_run_extracted_py = run_text_program


def run_vm_trace(instructions: List[str], fuel: int = 1000) -> _extracted_vm.VMState:
    """Execute a VM program and return the final state."""
    strict = _strict_backend_required()
    if _runner_available():
        try:
            return _run_extracted(instructions, fuel)
        except (FileNotFoundError, PermissionError, OSError):
            if strict:
                raise RuntimeError("strict backend policy: OCaml extracted runner failed")
    if strict and not _runner_available():
        raise RuntimeError(
            "strict backend policy: OCaml extracted runner not available at "
            + str(_RUNNER_PATH)
        )
    try:
        return _run_python(instructions, fuel)
    except Exception as e:
        raise RuntimeError("Coq-extracted Python VM failed: " + str(e)) from e


def run_vm(instructions: List[str], fuel: int = 1000) -> _extracted_vm.VMState:
    """Alias for run_vm_trace."""
    return run_vm_trace(instructions, fuel)
